import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F03: 合約負債與營收能見度 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F03_合約負債與營收能見度.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F03_合約負債與營收能見度.md"}'),l={name:"審計報告庫/財務審計/6239_力成/20260617/F03_合約負債與營收能見度.md"};function o(n,a,h,s,d,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="f03-合約負債與營收能見度-財務審計專家報告" tabindex="-1">F03: 合約負債與營收能見度 - 財務審計專家報告 <a class="header-anchor" href="#f03-合約負債與營收能見度-財務審計專家報告" aria-label="Permalink to &quot;F03: 合約負債與營收能見度 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>合約負債與未來收入的變動關係為何？訂單轉化為實質營收的速度是否出現停滯？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：合約負債1.33億→3.52億（+165%），客戶預付款意願增強；但僅佔季營收0.17%，主因封測隨時間認列收入非預收貨款模式。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至2026Q1最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>合約負債季度數據：2024Q4 1.46億→2025Q1 1.38億→2025Q2 1.84億→2025Q3 2.16億→2025Q4 2.59億→2026Q1 3.52億。連續五季增長，累計增幅141%。2026Q1季增率+36%，增速加快。合約負債/季營收比從2024Q3的0.07%提升至2026Q1的0.17%，雖絕對值不高但趨勢明確向好。做為封測服務廠，力成的合約負債主要來自客戶預付的NRE（一次性工程費用）或產能保留金，非賣斷式預收貨款，因此絕對水位低於製造業。真正反映訂單能見度的指標是產能利用率（封裝~90%、測試~85%），而非合約負債絕對值。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="訂單領先指標分析" tabindex="-1">訂單領先指標分析 <a class="header-anchor" href="#訂單領先指標分析" aria-label="Permalink to &quot;訂單領先指標分析&quot;">​</a></h3><p>力成合約負債從2024Q3的1.33億（近年低點）反轉向上，至2026Q1已達3.52億。對照同期營收走勢：2024年營收逐季下滑（Q1:183.3億→Q4:171.0億），合約負債同步在Q3觸底；2025年營收逐季回升（Q1:154.9億→Q4:214.1億），合約負債亦隨之擴張。合約負債變化與營收趨勢高度一致，未出現背離。2026Q1營收213.1億創近年單季次高，合約負債同步創下352M的新高，顯示客戶對後續封測需求的預付意願持續增強。</p><h3 id="能見度週期判定" tabindex="-1">能見度週期判定 <a class="header-anchor" href="#能見度週期判定" aria-label="Permalink to &quot;能見度週期判定&quot;">​</a></h3><p>力成的合約負債/日營收比約1.5天（2026Q1），相較於消費性電子或半導體設備廠（通常30-90天）極低。但這是封測服務業的本質特徵——力成收入來自持續性封裝測試服務（按月按完工進度認列），非預收大筆貨款再出貨的模式。能見度應從客戶長期合約與產能保留協議判斷。年報附註揭露112年11月與臻鼎科技簽訂產能保留協議（保證金3500萬美元），截至114年底已收回2040萬美元，顯示仍有長期產能承諾的客戶。管理層預期2026年全年營收逐季成長，先進封裝（FOPLP、HBM、CPO）2027年起接力量產。</p><h3 id="轉化效率壓力測試" tabindex="-1">轉化效率壓力測試 <a class="header-anchor" href="#轉化效率壓力測試" aria-label="Permalink to &quot;轉化效率壓力測試&quot;">​</a></h3><p>2025Q4合約負債259M，對應2026Q1營收213.1億，合約負債轉化率約為0.12%（259M/213.1B），速度極快但規模極小。重要觀察：合約負債持續增長而非降低，排除了「訂單去化過快、新單銜接不足」的風險。真正的能見度瓶頸不在合約負債，而在產能——封裝產能已達90%接近滿載，測試約85%，新增需求可能面臨交期延長。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>合約負債規模過小</strong>：僅3.52億（季營收0.17%），預測能力極弱。訂單能見度只能靠產能利用率與客戶法說口徑判定，缺乏量化指標。</li><li><strong>結構單薄</strong>：96.6%來自加工服務收入，非長期合約預收款，無法提供6-12個月前瞻能見度，反映封測代工產業本質。</li><li><strong>被動指標風險</strong>：合約負債上升是客戶預付的「結果」非「原因」。若AI需求減速，客戶停止預付，合約負債可能立即萎縮。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>連續五季增長趨勢明確</strong>：1.33億→3.52億（+165%），季增率加速。同期營收213.1億（+37.8% YoY），無背離。</li><li><strong>先進封裝NRE的先行指標</strong>：合約負債含客戶驗證FOPLP/光引擎的NRE費用。2026Q1創高可能反映AI客戶為2027年量產付工程費。</li><li><strong>產能利用率互補驗證</strong>：封裝~90%、測試~85%與合約負債同步走高，雙重驗證需求面健康。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>合約負債規模低由服務業商業模式決定，非競爭劣勢。產能接近滿載、月營收創高、合約負債連五季成長，短期動能無虞。關注FOPLP量產後能否拉高合約負債水位。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (balance_sheet 6239) + 數據採集器.py (finance 6239)</li><li>原始數據：FinMind TaiwanStockBalanceSheet (CurrentContractLiabilities)、TaiwanStockFinancialStatements (Revenue)</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2026-06-17</li><li>年報數據：2025_Q4_6239_合併.pdf (page 8，資產負債表合約負債科目)</li><li>法說會資訊：富果法說會備忘錄 20260428</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const b=e(l,[["render",o]]);export{u as __pageData,b as default};
